t[str, Pose]) -> str: feedback = "" ik_result = self.planner.inverse_kinematics_all(self.env.physics, pose_dict) for name, result in ik_result.items(): if result is None: pose = pose_dict[name] feedback += f"{name} {pose.pos_string}; " return feedback, ik_result def collision_feedback( self, llm_plan: LLMPathPlan, ik_result: Dict[str, np.ndarray] ) -> str: assert all([result is not None for result in ik_result.values()]), "Collision feedback should be called after ik feedback" feedback = "" target_qpos = np.concatenate( [ik_result[name][0] for name in self.robot_agent_names] ) # inhand_ids = llm_plan.get_inhand_ids(self.env.physics) allowed_collision_ids = llm_plan.get_allowed_collision_ids(self.env.physics) self.planner.set_inhand_info( self.env.physics, llm_plan.get_inhand_obj_info(self.env.physics) ) collided_body_pairs = self.planner.get_collided_links( qpos=target_qpos, physics=self.env.physics, allow_grasp=True, # check ids should already be set in at policy __init check_grasp_ids=allowed_collision_ids, show=0, ) adjusted_names = [] for name1, name2 in collided_body_pairs: name1 = self.robot_name_map.get(name1, name1) # convert panda to Bob name2 = self.robot_name_map.get(name2, name2) adjusted_names.append((name1, name2)) if len(collided_body_pairs) > 0: # make a string in the format [name: (x,y,z), name: (x,y,z), ...] feedback = "collided object pairs: " feedback += ", ".join( [f"{name1}-{name2}" for name1, name2 in adjusted_names] ) return feedback def path_feedback(self, llm_plan: LLMPathPlan) -> str: """ check if the waypoint steps are evenly spaced """ feedback = "" if self.llm_output_mode == "action_and_path": full_path = self.get_full_path(llm_plan) for agent_name, path in full_path.items(): stepwise_dist = [] step_pairs = [] for i in range(len(path)-1): stepwise_dist.append(np.linalg.norm(path[i+1][:3] - path[i][:3])) x,y,z = path[i][:3] x2,y2,z2 = path[i+1][:3] step_pairs.append( f"({x:.2f},{y:.2f},{z:.2f})-({x2:.2f},{y2:.2f},{z2:.2f})" ) stepwise_dist = np.array(stepwise_dist) max_dist_pair = f" Distance between {step_pairs[np.argmax(stepwise_dist)]} is {np.max(stepwise_dist):.2f}, too high" min_dist_pair = f" Distance between {step_pairs[np.argmin(stepwise_dist)]} is {np.min(stepwise_dist):.2f}, too low" _std = np.std(stepwise_dist) if _std > self.step_std_threshold: feedback += f"You must make {agent_name}'s path more evenly spaced:
{max_dist_pair}
{min_dist_pair}
 Overall Distance std: {_std:.2f}" return feedback def get_step_string(self, pose_dict) -> str: step_string = "" for agent_name, pose in pose_dict.items(): step_string += f"{agent_name} {pose.pos_string}; " return step_string[:-2] def single_step_feedback(self, llm_plan, pose_dict, step_type: str = "Goal") -> Tuple[bool, str]: step_string = self.get_step_string(pose_dict) feedback = f"{step_type} Step {step_string}:
 " reach = self.reach_feedback(pose_dict) all_passed = True if len(reach) > 0: all_passed = False feedback += f" - Reachability failed: Out of reach: {reach}
 " else: # feedback += " - Reach feedback: passed
 " ik_feedback, ik_result = self.ik_feedback(pose_dict) if len(ik_feedback) > 0: all_passed = False feedback += f" - IK failed: on {ik_feedback}
 " else: # feedback += " - IK feedback: passed
 " collision_feedback = self.collision_feedback(llm_plan, ik_result) if len(collision_feedback) > 0: all_passed = False feedback += f" - Collision detected: {collision_feedback}
 " # else: # feedback += " - Collision feedback: passed
 " if all_passed: # feedback = f"{step_type} Step {step_string}: All checks passed
" feedback = "" return all_passed, feedback def give_feedback(self, llm_plan: LLMPathPlan) -> Tuple[bool, str]: """ Given a parsed LLM plan, run task validations and provide feedback if needed """ feedback = f"[Environment Feedback]:
- Previous Plan:
{llm_plan.parsed_proposal}
" task_feedback = self.task_feedback(llm_plan) plan_passed = True if len(task_feedback) == 0: # feedback += "- Task Constraints: all satisfied
" target_passed, target_feedback = self.single_step_feedback( llm_plan, llm_plan.ee_target_poses, "- Goal") # if not target_passed: # print(target_feedback) # breakpoint() feedback += target_feedback plan_passed = plan_passed and target_passed if self.llm_output_mode == "action_and_path": failed_waypoints = 0 for pose_dict in llm_plan.ee_waypoints_list: step_passed, step_feedback = self.single_step_feedback(llm_plan, pose_dict, "- Waypoint") feedback += step_feedback if not step_passed: failed_waypoints += 1 waypoints_passed = failed_waypoints 0: feedback += f"- Path feedback: failed, {path_feedback}
" plan_passed = False else: plan_passed = False feedback += f"Task Constraints:
 faild, {task_feedback}
" # breakpoint() return plan_passed, feedback

import os import numpy as np from copy import deepcopy from PIL import Image import matplotlib.pyplot as plt import seaborn as sns import torch from typing import Dict, List from pydantic import dataclasses, validator from real_world.utils.generic import AllowArbitraryTypes from real_world.kinect import KinectClient from transformers import OwlViTProcessor, OwlViTForObjectDetection WS_CROP_X = (180, -120) WS_CROP_Y = (300, -380) Table workspace surface is 0.0 without suction gripper and -0.025 with the suction gripper WORKSPACE_SURFACE = -0.025 BIN_TOP = 0.1 tool_orientation = [2.22, -2.22, 0.0] @dataclasses.dataclass(config=AllowArbitraryTypes, frozen=True) class EnvState: color_im: np.ndarray # shape: (H, W, 3) depth_im: np.ndarray # shape: (H, W) objects: Dict[str, np.ndarray] # shape: (4,) (xmin, ymin, xmax, ymax) @validator("color_im") @classmethod def color_im_shape(cls, v: np.ndarray): if v.shape[2] != 3: raise ValueError("color_im must have shape (H, W, 3)") return v @validator("depth_im") @classmethod def depth_im_shape(cls, v: np.ndarray, values): if v.shape != values["color_im"].shape[:2]: raise ValueError("color_im and depth_im must have same (H, W)") return v @validator("objects") @classmethod def objects_shape(cls, v: Dict[str, np.ndarray]): for obj in v: if v[obj].shape != (4,): raise ValueError("objects must have shape (4,)") return v class RealEnv(): def __init__( self, bin_cam, task: str, all_objects: List[str], task_objects: List[str], output_name: str = None, ): self.bin_cam = bin_cam self.task = task self.all_objects = all_objects self.task_objects = task_objects if output_name is None: self.output_name = f"real_world/outputs/{self.task}/" else: self.output_name = f"real_world/outputs/{output_name}/" os.makedirs(self.output_name, exist_ok=True) self.robot_name = 'Bob' self.human_name = 'Alice' # Load OWL-ViT model self.model = OwlViTForObjectDetection.from_pretrained("google/owlvit-base-patch32") self.processor = OwlViTProcessor.from_pretrained("google/owlvit-base-patch32") self.timestep = 0 def get_obs(self, save=False) -> EnvState: # Get color and depth images from the kinect color_im, depth_im = self.bin_cam.get_camera_data() ws_color_im = color_im[WS_CROP_X[0]:WS_CROP_X[1], WS_CROP_Y[0]:WS_CROP_Y[1]] ws_depth_im = depth_im[WS_CROP_X[0]:WS_CROP_X[1], WS_CROP_Y[0]:WS_CROP_Y[1]] image = Image.fromarray(ws_color_im) text = self.all_objects # Get max probability bounding boxes for each object label inputs = self.processor(text=[text], images=image, return_tensors="pt") outputs = self.model(**inputs) target_sizes = torch.Tensor([image.size[::-1]]) results = self.processor.post_process(outputs=outputs, target_sizes=target_sizes) pred_scores = results[0]["scores"].detach().numpy() pred_labels, pred_boxes = results[0]["labels"].detach().numpy(), results[0]["boxes"].detach().numpy() objects = {} for label in np.unique(pred_labels): max_score_idx = np.argmax(pred_scores[np.where(pred_labels == label)]) max_box = pred_boxes[np.where(pred_labels == label)][max_score_idx] objects[text[label]] = max_box self.timestep += 1 if save: image.save(f"{self.output_name}/img_{self.timestep}.png") obs = EnvState( color_im=color_im, depth_im=depth_im, objects=objects, ) return obs def plot_preds(self, color_im, objects, save=False, show=True): fig, ax = plt.subplots(figsize=(12, 12 * color_im.shape[0] / color_im.shape[1])) ax.imshow(color_im) colors = sns.color_palette('muted', len(objects)) for label, c in zip(objects, colors): (xmin, ymin, xmax, ymax) = objects[label] ax.add_patch( plt.Rectangle((xmin, ymin), xmax - xmin, ymax - ymin, fill=False, color=c, linewidth=3)) if label in self.task_objects: ax.text(xmin-30, ymax+15, label, fontsize=22, bbox=dict(facecolor='white', alpha=0.8)) else: ax.text(xmin, ymin-10, label, fontsize=22, bbox=dict(facecolor='white', alpha=0.8)) plt.axis('off') fig.tight_layout() if show: plt.show() if save: fig.savefig(f"{self.output_name}/pred_{self.timestep}.png") def describe_task_context(self): raise NotImplementedError def chat_mode_prompt(self): raise NotImplementedError def get_action_prompt(self): raise NotImplementedError def get_system_prompt( self, mode="chat", obs = None, chat_history: List[Dict] = [], feedback_history: List[str] = [], include_comm_prompt=True, ): context = self.describe_task_context() if mode == "chat": comm_prompt = self.chat_mode_prompt() else: raise NotImplementedError history = '' round_num = len(chat_history) if len(chat_history) > 0: history = f"[History]
" for i, response in enumerate(chat_history): history += f"=== Round #{i}: === 
{response}
" scene_desp = f"=== Round {round_num}: === 
" + (self.describe_scene(obs.objects) if obs is not None else "") feedback_history = "
".join(feedback_history) if not include_comm_prompt: system_prompt = f"{context}
{history}
{scene_desp}
{feedback_history}" else: system_prompt = f"{context}
{history}
{scene_desp}
{feedback_history}
{comm_prompt}" breakdown = dict( task_context=context, comm_prompt=comm_prompt, scene_desp=scene_desp, feedback_history=feedback_history, ) return system_prompt, breakdown def pick_and_place_primitive(self, obs, pick_obj, place_where): if pick_obj not in obs.objects: raise Exception(f"PICK: {pick_obj} not detected") if place_where not in obs.objects: raise Exception(f"PLACE: {place_where} not detected") pick_pix = [int((obs.objects[pick_obj][0] + obs.objects[pick_obj][2])/2), int((obs.objects[pick_obj][1] + obs.objects[pick_obj][3])/2)] pick_pix = pick_pix[0] + WS_CROP_Y[0], pick_pix[1] + WS_CROP_X[0] place_pix = [int((obs.objects[place_where][0] + obs.objects[place_where][2])/2), int((obs.objects[place_where][1] + obs.objects[place_where][3])/2)] place_pix = place_pix[0] + WS_CROP_Y[0] + 20, place_pix[1] + WS_CROP_X[0] bin_cam_pose = np.loadtxt('real_world/cam_pose/cam2ur_pose.txt') bin_cam_depth_scale = np.loadtxt('real_world/cam_pose/camera_depth_scale.txt') # Get pick point in camera coordinates z = obs.depth_im[pick_pix[1], pick_pix[0]] * bin_cam_depth_scale x = (pick_pix[0]-self.bin_cam.color_intr[0, 2]) * \ z/self.bin_cam.color_intr[0, 0] y = (pick_pix[1]-self.bin_cam.color_intr[1, 2]) * \ z/self.bin_cam.color_intr[1, 1] if z == 0: return pick_point = np.asarray([x, y, z]) pick_point = np.append(pick_point, 1.0).reshape(4, 1) # Convert camera coordinates to robot coordinates pick_pos = np.dot(bin_cam_pose, pick_point) pick_pos = pick_pos[0:3, 0] # Move robot to target position only if it is above the table pick_pos[2] = max(pick_pos[2], WORKSPACE_SURFACE) self.robot.open_suction_sys() # Move robot to target position for pick if it is currently grasping nothing if self.robot.check_grasp() == False: self.robot.open_gripper() print("Moving robot to target position for pick...") postpick_pos = deepcopy(pick_pos) postpick_pos[2] += 0.2 # print("Pick position: ", pick_pos) self.robot.movel(list(pick_pos) + tool_orientation, 0.5, 0.1, blocking=True) self.robot.close_gripper() # print("Current grasp: ", self.robot.check_grasp()) while not self.robot.check_grasp(): pick_pos[2] -= 0.01 if pick_pos[2] < WORKSPACE_SURFACE: print("Reached workspace surface; cannot go lower") self.robot.open_gripper() break self.robot.movel(list(pick_pos) + tool_orientation, 0.05, 0.05, blocking=True) # print("Current grasp: ", self.robot.check_grasp()) self.robot.movel(list(postpick_pos) + tool_orientation, 0.5, 0.1, blocking=True) # Get place point in camera coordinates z = obs.depth_im[place_pix[1], place_pix[0]] * bin_cam_depth_scale x = (place_pix[0]-self.bin_cam.color_intr[0, 2]) * \ z/self.bin_cam.color_intr[0, 0] y = (place_pix[1]-self.bin_cam.color_intr[1, 2]) * \ z/self.bin_cam.color_intr[1, 1] if z == 0: return place_point = np.asarray([x, y, z]) place_point = np.append(place_point, 1.0).reshape(4, 1) # Convert camera coordinates to robot coordinates place_pos = np.dot(bin_cam_pose, place_point) place_pos = place_pos[0:3, 0] # Move robot to target position only if it is above the table place_pos[2] = max(place_pos[2], BIN_TOP) # Move robot to target position for pick if it is currently grasping something if self.robot.check_grasp() == True: print("Moving robot to target position for place...") prepostplace_pos = deepcopy(place_pos) prepostplace_pos[2] += 0.1 # print("Place position: ", place_pos) self.robot.movel(list(prepostplace_pos) + tool_orientation, 0.5, 0.1, blocking=True) self.robot.movel(list(place_pos) + tool_orientation, 0.5, 0.1, blocking=True) self.robot.open_gripper() # print("Current grasp: ", self.robot.check_grasp()) self.robot.movel(list(prepostplace_pos) + tool_orientation, 0.5, 0.1, blocking=True) self.robot.close_suction_sys() self.robot.home() if __name == "__main__": # Set up top-down kinect and task environment bin_cam = KinectClient(ip='128.59.23.32', port=8080) env = RealEnv( bin_cam=bin_cam, task='block_in_cup', all_objects=["red cup", "yellow cup", "blue triangular block", "green cube", "wooden bin"], task_objects=["blue triangular block", "green cube"]) while True: obs = env.get_obs(True) ws_color_im = obs.color_im[WS_CROP_X[0]:WS_CROP_X[1], WS_CROP_Y[0]:WS_CROP_Y[1]] env.plot_preds(ws_color_im, obs.objects, save=True, show=True) breakpoint()

import os import cv2 import numpy as np from PIL import Image import matplotlib.pyplot as plt import seaborn as sns import torch from typing import Dict from pydantic import dataclasses, validator from real_world.utils.generic import AllowArbitraryTypes from real_world.kinect import KinectClient from transformers import OwlViTProcessor, OwlViTForObjectDetection WS_CROP_X = (180, -120) WS_CROP_Y = (300, -380) TASK = 'block_in_cup' ALL_OBJECTS = ["blue cup", "yellow cup", "purple cup", "red hexagonal block", "yellow block", "strawberry toy", "wooden bin"] TASK_OBJECTS = ["red hexagonal block", "yellow block", "strawberry toy"] @dataclasses.dataclass(config=AllowArbitraryTypes, frozen=True) class EnvState: color_im: np.ndarray # shape: (H, W, 3) depth_im: np.ndarray # shape: (H, W) objects: Dict[str, np.ndarray] # shape: (4,) (xmin, ymin, xmax, ymax) @validator("color_im") @classmethod def color_im_shape(cls, v: np.ndarray): if v.shape[2] != 3: raise ValueError("color_im must have shape (H, W, 3)") return v @validator("depth_im") @classmethod def depth_im_shape(cls, v: np.ndarray, values): if v.shape != values["color_im"].shape[:2]: raise ValueError("color_im and depth_im must have same (H, W)") return v @validator("objects") @classmethod def objects_shape(cls, v: Dict[str, np.ndarray]): for obj in v: if v[obj].shape != (4,): raise ValueError("objects must have shape (4,)") return v class Task(): def __init__( self, bin_cam): self.bin_cam = bin_cam self.task = TASK self.all_objects = ALL_OBJECTS self.task_objects = TASK_OBJECTS self.output_name = f"real_world/outputs/{self.task}/" os.makedirs(self.output_name, exist_ok=True) # Load OWL-ViT model self.model = OwlViTForObjectDetection.from_pretrained("google/owlvit-base-patch32") self.processor = OwlViTProcessor.from_pretrained("google/owlvit-base-patch32") self.timestep = 0 def get_obs(self) -> EnvState: # Get color and depth images from the kinect color_im, depth_im = bin_cam.get_camera_data() bgr_data = cv2.cvtColor(color_im, cv2.COLOR_RGB2BGR) ws_color_im = color_im[WS_CROP_X[0]:WS_CROP_X[1], WS_CROP_Y[0]:WS_CROP_Y[1]] ws_depth_im = depth_im[WS_CROP_X[0]:WS_CROP_X[1], WS_CROP_Y[0]:WS_CROP_Y[1]] image = Image.fromarray(ws_color_im) text = ALL_OBJECTS inputs = self.processor(text=[text], images=image, return_tensors="pt") outputs = self.model(**inputs) # Target image sizes (height, width) to rescale box predictions [batch_size, 2] target_sizes = torch.Tensor([image.size[::-1]]) # Convert outputs (bounding boxes and class logits) to COCO API results = self.processor.post_process(outputs=outputs, target_sizes=target_sizes) # Get prediction scores pred_scores = results[0]["scores"].detach().numpy() # Get prediction labels and boundary boxes pred_labels, pred_boxes = results[0]["labels"].detach().numpy(), results[0]["boxes"].detach().numpy() objects = {} for label in np.unique(pred_labels): max_score_idx = np.argmax(pred_scores[np.where(pred_labels == label)]) max_score = pred_scores[np.where(pred_labels == label)][max_score_idx] max_box = pred_boxes[np.where(pred_labels == label)][max_score_idx] # print(f"Detected {text[label]} with confidence {round(max_score.item(), 3)} at location {max_box}") objects[text[label]] = max_box self.timestep += 1 image.save(f"{self.output_name}/img_{self.timestep}.png") obs = EnvState( color_im=ws_color_im, depth_im=ws_depth_im, objects=objects, ) return obs def plot_preds(self, color_im, objects, save=False): fig, ax = plt.subplots(figsize=(12, 12 * color_im.shape[0] / color_im.shape[1])) ax.imshow(color_im) colors = sns.color_palette('muted', len(objects)) for label, c in zip(objects, colors): (xmin, ymin, xmax, ymax) = objects[label] ax.add_patch( plt.Rectangle((xmin, ymin), xmax - xmin, ymax - ymin, fill=False, color=c, linewidth=3)) if label in self.task_objects: ax.text(xmin-30, ymax+15, label, fontsize=22, bbox=dict(facecolor='white', alpha=0.8)) else: ax.text(xmin, ymin-10, label, fontsize=22, bbox=dict(facecolor='white', alpha=0.8)) plt.axis('off') fig.tight_layout() plt.show() if save: fig.savefig(f"{self.output_name}/pred_{self.timestep}.png", bbox_inches='tight', pad_inches=0) def plot_preds_rotated(self, color_im, objects, save=False): fig, ax = plt.subplots(figsize=(12, 12 * color_im.shape[0] / color_im.shape[1])) from scipy import ndimage # ax.imshow(ndimage.rotate(color_im, 180)) colors = sns.color_palette('muted', len(objects)) for label, c in zip(objects, colors): (xmin, ymin, xmax, ymax) = objects[label] xmin = color_im.shape[1] - xmin xmax = color_im.shape[1] - xmax ymin = color_im.shape[0] - ymin ymax = color_im.shape[0] - ymax ax.add_patch( plt.Rectangle((xmin, ymin), xmax - xmin, ymax - ymin, fill=False, color=c, linewidth=3)) if label in self.task_objects: ax.text(xmax-45, ymin+15, label, fontsize=22, bbox=dict(facecolor='white', alpha=0.8)) else: ax.text(xmax, ymax-10, label, fontsize=22, bbox=dict(facecolor='white', alpha=0.8)) plt.axis('off') fig.tight_layout() plt.show() if save: fig.savefig(f"{self.output_name}/pred_{self.timestep}.png", bbox_inches='tight', pad_inches=0) def describe_scene( self, objects, cup="cup", bin="wooden bin", ): scene_desp = "[Scene description]
" assert bin in objects, f"{bin} not detected" bin_box = objects[bin] bin_center = (bin_box[0]+bin_box[2])/2, (bin_box[1]+bin_box[3])/2 bin_size = (bin_box[2]-bin_box[0])/2 for obj in self.task_objects: obj_box = objects[obj] obj_center = (obj_box[0]+obj_box[2])/2, (obj_box[1]+obj_box[3])/2 dist = ((obj_center[0]-bin_center[0])**2 + (obj_center[1]-bin_center[1])**2)**0.5 if dist < bin_size: # determine if the object is inside the wooden bin scene_desp += f"{obj}: in {bin}
" elif cup not in obj: # determine if the object is inside a cup inside_sth = False for other_obj in objects: if cup in other_obj: other_obj_box = objects[other_obj] other_obj_center = (other_obj_box[0]+other_obj_box[2])/2, (other_obj_box[1]+other_obj_box[3])/2 dist_to_cup = ((obj_center[0]-other_obj_center[0])**2 + (obj_center[1]-other_obj_center[1])**2)**0.5 cup_size = (other_obj_box[2]-other_obj_box[0])/2 if dist_to_cup < cup_size: scene_desp += f"{obj}: in {other_obj}
" inside_sth = True if not inside_sth: # determine if the object is on the table scene_desp += f"{obj}: on table
" return scene_desp if __name == "__main__": # Set up top-down kinect and task environment bin_cam = KinectClient(ip='128.59.23.32', port=8080) env = Task(bin_cam=bin_cam) while True: obs = env.get_obs() env.plot_preds(obs.color_im, obs.objects, False) env.plot_preds_rotated(obs.color_im, obs.objects, True) scene_desp = env.describe_scene(obs.objects) print(scene_desp) breakpoint()

